import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './ValorantPage.css';
import Header from './Header';

function ValorantPage() {
  const [matches, setMatches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Состояние формы
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    date: ''
  });

  // Загрузка объявлений при монтировании
  useEffect(() => {
    loadMatches();
  }, []);

  const loadMatches = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/matches/valorant', {
        credentials: 'include'
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка загрузки');
      setMatches(data.matches || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // Обработка изменения полей формы
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Отправка нового объявления
  const handleSubmit = async (e) => {
    e.preventDefault();
    const { title, description, date } = formData;
    if (!title || !description || !date) {
      alert('Заполните все поля');
      return;
    }

    try {
      const response = await fetch('/api/matches', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          game: 'valorant',
          title,
          description,
          date: new Date(date).toISOString()
        }),
        credentials: 'include'
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.error || 'Ошибка создания');

      // Добавляем новое объявление в список
      setMatches((prev) => [...prev, data.match]);
      setIsModalOpen(false);
      setFormData({ title: '', description: '', date: '' });
    } catch (err) {
      alert(err.message);
    }
  };

  if (loading) return <div className="loading">Загрузка объявлений...</div>;

  return (
    <div className="valorant-page">
      <Header />
      <div className="valorant-content">
        <h1>VALORANT</h1>
        <p>
          Valorant — это динамичный тактический шутер, где молниеносная стрельба
          переплетается с уникальными способностями агентов, превращая каждый раунд
          в захватывающее противостояние умов и реакции.
        </p>
      </div>

      <div className="announcement-wrapper">
        <div className="valorant-announcements">
          {matches.length === 0 ? (
            <p className="no-announcements">Пока нет объявлений. Будьте первым!</p>
          ) : (
            matches.map((match) => (
              <div key={match.id} className="announcement-item">
                <h3>{match.title}</h3>
                <p>{match.description}</p>
                <p className="match-date">
                  🕒 {new Date(match.date).toLocaleString()}
                </p>
                <p className="match-author">👤 {match.author || 'Неизвестный'}</p>
                <p className="match-status">
                  Статус: {match.status === 'open' ? '🟢 Открыто' : '🔴 Закрыто'}
                </p>
              </div>
            ))
          )}
        </div>

        <button className="add-announcement-btn" onClick={() => setIsModalOpen(true)}>
          Разместить объявление
        </button>
      </div>

      {/* Модальное окно создания объявления */}
      {isModalOpen && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2>Новое объявление для Valorant</h2>
            <form onSubmit={handleSubmit}>
              <label>
                Заголовок
                <input
                  type="text"
                  name="title"
                  value={formData.title}
                  onChange={handleChange}
                  placeholder="Введите заголовок"
                  required
                />
              </label>
              <label>
                Описание
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleChange}
                  placeholder="Опишите, кого ищете"
                  rows="4"
                  required
                />
              </label>
              <label>
                Дата и время игры
                <input
                  type="datetime-local"
                  name="date"
                  value={formData.date}
                  onChange={handleChange}
                  required
                />
              </label>
              <div className="modal-buttons">
                <button type="submit" className="submit-btn">
                  Опубликовать
                </button>
                <button
                  type="button"
                  className="cancel-btn"
                  onClick={() => setIsModalOpen(false)}
                >
                  Отмена
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default ValorantPage;
